mapper.select:
select
o.id, o.amount, o.status, o.description, o.order_time,
o.order_type, o.payment_type,su.user_name
from `order` o
    left join sys_user su on o.user_id = su.user_id
where 1 = 1 and o.is_deleted = 0

        and o.id = #{dto.id}


        and o.user_id = #{userId}


        and su.user_name like concat('%', #{dto.userName}, '%')


        and o.status = #{dto.status}


        and o.order_type = #{dto.orderType}


        and o.order_time >= #{dto.orderCreateTime}


        and o.order_time <= #{dto.orderEndTime}


        and o.payment_period = #{dto.paymentPeriod}


        and o.payment_type = #{dto.paymentType}


        and o.description like concat('%', #{dto.description}, '%')

    order by o.create_time desc

select c.id as commodityId, c.commodity_name as commodityName, cc.id as categoryId, cc.category_name as categoryName, count(oc.id) as salesCount from `order` o inner join order_commodity oc on o.id = oc.order_id inner join commodity c on oc.commodity_id = c.id inner join commodity_category cc on c.category_id = cc.id where o.is_deleted = 0 and oc.is_deleted = 0 and c.is_deleted = 0 and cc.is_deleted = 0 and o.status in ('WAIT_ALLOCATION_RESOURCES', 'COMPLETED') and o.order_type in ('add', 'renew') and o.create_time >= date_sub(curdate(), interval 30 day)
and cc.id = #{categoryId}
group by c.id, c.commodity_name, cc.id, cc.category_name order by salesCount desc
